import{_ as o,o as r,c as e,ae as s}from"./chunks/framework.BIONGpTb.js";const p=JSON.parse('{"title":"Eclipse Docks vs Eclipse Theia","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/docks-vs-theia.md","filePath":"concepts/docks-vs-theia.md"}'),n={name:"concepts/docks-vs-theia.md"};function a(g,t,i,d,l,c){return r(),e("div",null,[...t[0]||(t[0]=[s('<h1 id="eclipse-docks-vs-eclipse-theia" tabindex="-1">Eclipse Docks vs Eclipse Theia <a class="header-anchor" href="#eclipse-docks-vs-eclipse-theia" aria-label="Permalink to &quot;Eclipse Docks vs Eclipse Theia&quot;">​</a></h1><p><a href="https://github.com/eclipse-docks/core" target="_blank" rel="noreferrer">Eclipse Docks</a> and <a href="https://theia-ide.org/" target="_blank" rel="noreferrer">Eclipse Theia</a> are both <strong>Eclipse Foundation</strong> technology projects for building tools and IDEs. They solve different problems: <strong>Theia</strong> is a <strong>platform</strong> close to <strong>VS Code</strong> (including a Node backend and VS Code extension compatibility); <strong>Docks</strong> is a <strong>lightweight browser shell</strong> for modular, IDE-<strong>like</strong> and dashboard-style apps with <strong>your</strong> backends.</p><p>Neither product replaces the other in every scenario. Use this page to compare them in depth.</p><h2 id="at-a-glance" tabindex="-1">At a glance <a class="header-anchor" href="#at-a-glance" aria-label="Permalink to &quot;At a glance&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th><strong>Eclipse Docks</strong></th><th><strong>Eclipse Theia</strong></th></tr></thead><tbody><tr><td><strong>Runtime shape</strong></td><td><strong>Browser SPA</strong> — core UI and extensions run in the client; integrate backends with <code>fetch</code> or your own APIs.</td><td><strong>Frontend + backend</strong> — UI plus a <strong>Node.js</strong> server; <strong>JSON-RPC / WebSockets / HTTP</strong> (<a href="https://theia-ide.org/docs/architecture/" target="_blank" rel="noreferrer">architecture</a>).</td></tr><tr><td><strong>Typical deployment</strong></td><td>Static or hosted web app (e.g. Vite build); <strong>no</strong> required IDE server in the framework.</td><td>Desktop (<strong>Electron</strong>), browser + <strong>remote</strong> server, or hybrid — <a href="https://theia-ide.org/docs/" target="_blank" rel="noreferrer">Theia docs</a>.</td></tr><tr><td><strong>Scalability</strong></td><td>Shell ships as <strong>static assets</strong> (CDN, caching). No Docks-specific server tier for the UI; work is <strong>per browser</strong> or on <strong>APIs you own</strong>.</td><td><strong>Node backend</strong> is part of many setups; <strong>cloud / multi-user</strong> deployments must <strong>scale</strong> that tier (connections, language services, file access, etc.).</td></tr><tr><td><strong>Extension model</strong></td><td><strong>npm</strong> packages; <code>extensionRegistry</code>, contributions, commands.</td><td><strong>Theia extensions</strong>, <strong>VS Code extensions</strong>, plugins — <a href="https://theia-ide.org/docs/extensions/" target="_blank" rel="noreferrer">extensions</a>.</td></tr><tr><td><strong>VS Code extensions / Open VSX</strong></td><td><strong>Planned:</strong> <strong>browser-only</strong> extensions from <a href="https://open-vsx.org/" target="_blank" rel="noreferrer">Open VSX</a> with a <strong>subset</strong> of the <code>vscode</code> API (not full VS Code parity).</td><td><strong>Built-in:</strong> VS Code compatibility and <strong>Open VSX</strong> as first-class.</td></tr><tr><td><strong>Out-of-the-box IDE depth</strong></td><td><strong>Composable:</strong> Monaco, LSP, terminal, etc. as <strong>optional</strong> extensions you wire.</td><td><strong>Platform:</strong> language services, terminal, Git, debug — closer to a <strong>full IDE shell</strong> when you need that breadth.</td></tr><tr><td><strong>Desktop / offline / PWA</strong></td><td><strong>Web-first.</strong> Apps are <strong>PWA-ready</strong> (standard SPA): you can add a <strong>web app manifest</strong>, <strong>service worker</strong>, and <strong>offline</strong> behavior for the shell and cached assets. Optional <strong>desktop</strong> = wrap the SPA (e.g. Electron/Tauri).</td><td><strong>Electron</strong> and hybrid deployments are <strong>first-class</strong> <a href="https://theia-ide.org/docs/" target="_blank" rel="noreferrer">Theia docs</a>. Browser Theia often still expects an <strong>online</strong> backend for full IDE features.</td></tr><tr><td><strong>Language / remote tooling</strong></td><td>You decide where heavy work runs: <strong>browser</strong> (e.g. WASM), <strong>your</strong> servers, or hybrid — <strong>bring your own</strong> architecture.</td><td>Often <strong>centralizes</strong> language and file access on the <strong>Theia backend</strong> in cloud scenarios.</td></tr><tr><td><strong>Maturity &amp; ecosystem</strong></td><td>Newer project; smaller ecosystem; good when you want a <strong>small, readable</strong> core.</td><td>Longer track record; <strong>larger</strong> ecosystem, examples, and product adoptions.</td></tr><tr><td><strong>Best fit</strong></td><td>Custom <strong>dashboards</strong>, domain <strong>web</strong> tools, IDE-<strong>like</strong> UX with a <strong>small</strong> core and full control of the shell.</td><td>Products that should feel like <strong>VS Code</strong> or a <strong>cloud / desktop IDE</strong> with <strong>two-process</strong> architecture and VS Code extension compatibility.</td></tr><tr><td><strong>Standards &amp; longevity</strong></td><td><strong>Shell</strong> is <strong>browser-native</strong> (Web APIs, ES modules, web components). You ride the <strong>same</strong> long-term curve as the <strong>open web platform</strong>—PWA, <strong>Workers</strong>, <strong>WASM</strong>, storage, security—without a <strong>mandatory</strong> non-browser IDE process for the UI.</td><td>Strong <strong>web</strong> frontend, but the <strong>product</strong> story includes <strong>Node</strong>, <strong>VS Code</strong> APIs, and <strong>Theia</strong>’s own evolution—you optimize for that <strong>stack</strong>, not only TC39/W3C.</td></tr></tbody></table><h2 id="browser-standards-and-future-proofing" tabindex="-1">Browser standards and future-proofing <a class="header-anchor" href="#browser-standards-and-future-proofing" aria-label="Permalink to &quot;Browser standards and future-proofing&quot;">​</a></h2><p>No architecture is <strong>guaranteed</strong> future-proof: products still depend on <strong>npm packages</strong>, <strong>tooling</strong> (Vite, TypeScript), and <strong>browser</strong> engines that change over time.</p><p><strong>Eclipse Docks</strong> (as a <strong>pure client shell</strong>) aligns the <strong>application tier</strong> with <strong>standards-track</strong> technology: the UI runs where <strong>HTML, CSS, JavaScript, and Web APIs</strong> run. New capabilities—<strong>better WASM</strong>, <strong>smarter</strong> service workers, <strong>fine-grained</strong> permissions, <strong>faster</strong> IndexedDB/OPFS—accrue to your app <strong>without</strong> redesigning a proprietary <strong>in-framework</strong> desktop runtime for the shell. Tradeoff: you <strong>compose</strong> IDE features yourself (Monaco, LSP, etc.) rather than inheriting a full IDE host.</p><p><strong>Theia</strong> future-proofs in a <strong>different</strong> dimension: it tracks <strong>VS Code</strong> extension APIs, <strong>LSP</strong>, and a <strong>mature</strong> IDE <strong>backend</strong> model. That is <strong>excellent</strong> if your product roadmap is “stay close to VS Code.” It is a <strong>larger</strong> bet on that <strong>ecosystem</strong> than on “browser-only” minimalism.</p><p>Choose <strong>Docks</strong> when you want <strong>maximum</strong> alignment with <strong>portable, browser-first</strong> delivery; choose <strong>Theia</strong> when you want <strong>maximum</strong> alignment with the <strong>VS Code / cloud IDE</strong> platform.</p><h2 id="how-to-choose" tabindex="-1">How to choose <a class="header-anchor" href="#how-to-choose" aria-label="Permalink to &quot;How to choose&quot;">​</a></h2><ul><li>Prefer <strong>Theia</strong> when you need a <strong>VS Code–class</strong> platform: <strong>backend</strong>, <strong>Open VSX</strong>, full <strong>VS Code extension</strong> host, and established <strong>cloud IDE</strong> patterns.</li><li>Prefer <strong>Docks</strong> when you want a <strong>minimal web-first shell</strong> (tabs, commands, workspace) and <strong>your</strong> APIs; <strong>Open VSX</strong> browser extensions are <strong>planned</strong> as a <strong>gradual</strong>, subset-API path—not parity with every VS Code extension.</li></ul><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="/docs/concepts/architecture.html">Architecture</a> — Eclipse Docks layers and concepts.</li><li><a href="/docs/concepts/security.html">Security and safety</a> — trust model for extensions and the browser.</li><li><a href="https://theia-ide.org/docs/architecture/" target="_blank" rel="noreferrer">Eclipse Theia — Architecture</a> — official Theia overview.</li></ul>',14)])])}const u=o(n,[["render",a]]);export{p as __pageData,u as default};
